import React from "react";

function App() {
  return (
    <div style={{
      padding:"40px",
      fontFamily:"Arial",
      textAlign:"center",
      background:"#0f172a",
      color:"white",
      minHeight:"100vh"
    }}>
      <h1>ResumeX AI</h1>
      <p>Smart Resume Screening & Job Matching System</p>

      <div style={{marginTop:"30px"}}>
        <button style={btn}>Upload Resume</button>
        <button style={btn}>Add Job</button>
        <button style={btn}>View Results</button>
      </div>
    </div>
  );
}

const btn = {
  margin:"10px",
  padding:"12px 20px",
  border:"none",
  borderRadius:"8px",
  cursor:"pointer"
};

export default App;
